visual_assets.description_css:
#root {
  position: relative;
  z-index: 1;
  width: 100%;
  height: 100%;
  opacity: 0.8;
  padding:
    var(--root-pad-top, 170px)
    var(--root-pad-x, 94px)
    var(--root-pad-bottom, 172px);
}
.layout {
  height: 100%;
  display: grid;
  grid-template-columns: minmax(0, 1fr) var(--side-width, 260px);
  gap: var(--layout-gap, 42px);
  align-items: stretch;
  min-height: 0;
}
.hero {
  position: relative;
  display: flex;
  flex-direction: column;
  justify-content: flex-start;
  gap: var(--hero-stack-gap, 18px);
  min-width: 0;
  padding: var(--hero-pad-y, 62px) var(--hero-pad-x, 68px);
  border-radius: 34px;
  background:
    linear-gradient(180deg, rgba(255,255,255,0.06), rgba(255,255,255,0.02)),
    rgba(10, 10, 12, 0.46);
  border: 1px solid rgba(255, 255, 255, 0.14);
  box-shadow:
    0 30px 90px rgba(0, 0, 0, 0.45),
    inset 0 1px 0 rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(14px);
  overflow: hidden;
}
.hero::before {
  content: "";
  position: absolute;
  top: -80px;
  left: -80px;
  width: 260px;
  height: 260px;
  border-radius: 50%;
  background: radial-gradient(circle, color-mix(in srgb, #ff6b6b 46%, transparent), transparent 72%);
  filter: blur(8px);
}
.hero::after {
  content: "";
  position: absolute;
  right: -120px;
  bottom: -120px;
  width: 300px;
  height: 300px;
  border-radius: 50%;
  background: radial-gradient(circle, color-mix(in srgb, #ff6b6b 38%, transparent), transparent 72%);
  filter: blur(16px);
}
.kicker {
  position: relative;
  display: inline-flex;
  width: fit-content;
  align-items: center;
  gap: 12px;
  padding: 11px 16px;
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(255, 255, 255, 0.14);
  color: rgba(255,255,255,0.82);
  font-size: var(--kicker-size, 16px);
  font-weight: 700;
  letter-spacing: var(--kicker-spacing, 0.24em);
  text-transform: uppercase;
}
.kicker::before {
  content: "";
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: #ff6b6b;
  box-shadow: 0 0 14px color-mix(in srgb, #ff6b6b 92%, transparent);
}
h1 {
  position: relative;
  margin: 0;
  max-width: 100%;
  font-size: var(--description-title-size, 118px);
  line-height: var(--description-title-line-height, 0.9);
  letter-spacing: -0.06em;
  font-weight: 900;
  color: white;
  text-wrap: balance;
  overflow-wrap: normal;
  word-break: keep-all;
  hyphens: none;
}
.tagline {
  position: relative;
  max-width: var(--tagline-max-width, 680px);
  margin: 0;
  font-size: var(--tagline-size, 30px);
  line-height: 1.45;
  color: rgba(244, 247, 251, 0.92);
  font-weight: 500;
  text-wrap: pretty;
}
.meta {
  position: relative;
  display: flex;
  gap: 14px;
  flex-wrap: wrap;
  margin-top: auto;
  padding-top: var(--meta-padding-top, 22px);
}
.chip {
  padding: 12px 16px;
  border-radius: 14px;
  background: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(255, 255, 255, 0.12);
  color: rgba(244, 247, 251, 0.74);
  font-size: var(--chip-size, 16px);
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}
.side {
  display: grid;
  grid-template-rows: 1fr 1fr;
  gap: 20px;
  min-height: 0;
}
.stat {
  position: relative;
  padding: 28px 24px;
  border-radius: 26px;
  background:
    linear-gradient(180deg, rgba(255,255,255,0.06), rgba(255,255,255,0.02)),
    rgba(9, 9, 10, 0.48);
  border: 1px solid rgba(255,255,255,0.12);
  box-shadow: inset 0 1px 0 rgba(255,255,255,0.08);
  backdrop-filter: blur(12px);
  display: flex;
  flex-direction: column;
  justify-content: flex-end;
  min-height: 0;
  overflow: hidden;
}
.stat::before {
  content: "";
  position: absolute;
  left: 20px;
  right: 20px;
  top: 20px;
  height: 2px;
  background: linear-gradient(90deg, rgba(255,255,255,0.05), #ff6b6b, rgba(255,255,255,0.05));
}
.stat .value {
  position: relative;
  font-size: var(--stat-value-size, 58px);
  line-height: 0.92;
  font-weight: 900;
  letter-spacing: -0.04em;
  color: white;
}
.stat .label {
  position: relative;
  margin-top: 10px;
  font-size: var(--stat-label-size, 15px);
  font-weight: 700;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: rgba(255,255,255,0.62);
}
.stat .note {
  position: relative;
  margin-top: 16px;
  font-size: var(--stat-note-size, 16px);
  line-height: 1.45;
  color: rgba(255,255,255,0.74);
}

visual_assets.logo_css:
.frame {
  position: absolute;
  inset: var(--frame-inset, 62px);
  border-radius: 42px;
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.04), rgba(255, 255, 255, 0.015)),
    rgba(14, 14, 16, 0.64);
  border: 1px solid rgba(255, 255, 255, 0.12);
  box-shadow:
    0 35px 100px rgba(0, 0, 0, 0.55),
    inset 0 1px 0 rgba(255, 255, 255, 0.08),
    inset 0 -24px 40px rgba(0, 0, 0, 0.35);
  backdrop-filter: blur(14px);
  overflow: hidden;
}
.frame::before,
.frame::after {
  content: "";
  position: absolute;
  width: 320px;
  height: 320px;
  border-radius: 999px;
  filter: blur(18px);
  opacity: 0.72;
}
.frame::before {
  top: -96px;
  left: -82px;
  background: radial-gradient(circle, color-mix(in srgb, #ff6b6b 75%, white 25%), transparent 72%);
}
.frame::after {
  right: -100px;
  bottom: -120px;
  background: radial-gradient(circle, color-mix(in srgb, #ff6b6b 68%, black 12%), transparent 72%);
}
.rings {
  position: absolute;
  inset: 0;
  display: grid;
  place-items: center;
  pointer-events: none;
}
.ring {
  position: absolute;
  border-radius: 50%;
  border: 1px solid rgba(255, 255, 255, 0.12);
  box-shadow: 0 0 0 1px color-mix(in srgb, #ff6b6b 22%, transparent) inset;
}
.ring.one { width: 610px; height: 610px; }
.ring.two { width: 470px; height: 470px; }
.ring.three { width: 310px; height: 310px; }
.brackets {
  position: absolute;
  inset: var(--bracket-inset, 112px);
  pointer-events: none;
}
.brackets span {
  position: absolute;
  width: 92px;
  height: 92px;
  border-color: rgba(255, 255, 255, 0.24);
  border-style: solid;
  opacity: 0.88;
}
.brackets .tl { top: 0; left: 0; border-width: 2px 0 0 2px; }
.brackets .tr { top: 0; right: 0; border-width: 2px 2px 0 0; }
.brackets .bl { bottom: 0; left: 0; border-width: 0 0 2px 2px; }
.brackets .br { bottom: 0; right: 0; border-width: 0 2px 2px 0; }
.content {
  position: relative;
  z-index: 2;
  height: 100%;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-width: 0;
  padding:
    var(--content-pad-top, 110px)
    var(--content-pad-x, 110px)
    var(--content-pad-bottom, 94px);
  text-align: center;
}
.eyebrow {
  margin-bottom: 26px;
  padding: 10px 18px 11px;
  border-radius: 999px;
  border: 1px solid rgba(255, 255, 255, 0.14);
  background: rgba(255, 255, 255, 0.05);
  font-size: var(--eyebrow-size, 18px);
  font-weight: 700;
  letter-spacing: var(--eyebrow-spacing, 0.32em);
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.82);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.1);
}
.mark {
  position: relative;
  line-height: 0.82;
  font-size: var(--mark-size, 320px);
  font-weight: 900;
  letter-spacing: -0.08em;
  text-transform: uppercase;
  color: #f4f7fb;
  text-shadow:
    0 0 18px rgba(255, 255, 255, 0.28),
    0 0 46px rgba(255, 255, 255, 0.18),
    0 26px 65px rgba(0, 0, 0, 0.48);
}
.mark::after {
  content: "";
  position: absolute;
  left: 6%;
  right: 6%;
  top: 54%;
  height: 18px;
  border-radius: 999px;
  background: linear-gradient(90deg, transparent, #ff6b6b, transparent);
  box-shadow: 0 0 18px color-mix(in srgb, #ff6b6b 82%, transparent);
  transform: skewX(-18deg);
}
.title {
  margin-top: 18px;
  max-width: var(--title-max-width, 88%);
  font-size: var(--title-size, 74px);
  line-height: var(--title-line-height, 0.94);
  font-weight: 900;
  letter-spacing: -0.04em;
  text-transform: uppercase;
  color: white;
  text-wrap: balance;
  overflow-wrap: normal;
  word-break: keep-all;
  hyphens: none;
}
.sub {
  margin-top: 22px;
  max-width: var(--sub-max-width, 660px);
  font-size: var(--sub-size, 24px);
  line-height: 1.45;
  color: rgba(255, 255, 255, 0.74);
  letter-spacing: 0.02em;
  text-wrap: pretty;
}
.rail {
  position: absolute;
  left: var(--rail-inset, 110px);
  right: var(--rail-inset, 110px);
  bottom: 72px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 16px;
  font-size: var(--rail-size, 18px);
  font-weight: 700;
  letter-spacing: var(--rail-spacing, 0.26em);
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.56);
}
.rail span {
  min-width: 0;
}
.rail::before {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  top: -20px;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.10), transparent);
}
.rail .warn {
  color: color-mix(in srgb, #ff6b6b 76%, white 24%);
}
